    "key": ".claude/skills/spec-driven-development/references/templates/sdd-config.yml",
    "contentType": "text/yaml; charset=utf-8",
    "content": "# SDD configuration — controls how spec-reviewer and doc-updater agents behave on this project.\n# This file is read by both agents at the start of every run.\n\n# Mode: interactive | auto | unleashed\n#\n# interactive: confirm every fix before applying. Safe for new SDD users.\n# auto:        apply SAFE+RISKY fixes silently on the current branch.\n#              Escalate JUDGMENT calls to sdd/.review-needed.md.\n# unleashed:   apply everything (including JUDGMENT) on the current branch.\n#              Conservative defaults preserve information without overwriting intent.\n#              Walk-away autopilot — come back to per-category commits, git revert\n#              any unwanted change. No PR, no branch creation.\nmode: interactive\n\n# enforce_tdd: when true, spec-reviewer enforces the TDD contract on every run:\n#   - Downgrades Implemented REQs without test coverage to Partial\n#   - Flags Planned/Partial REQs with source code but no test (HIGH finding)\n#   - Runs test quality heuristics (AC count vs test count, tautology\n#     detection, skipped-test detection) against every test file\n#\n# When false, spec-reviewer only writes sdd/.coverage-report.md without\n# modifying the spec.\n#\n# Forced to true in unleashed mode (commits land on the current branch; TDD enforcement is non-negotiable).\n# Default true — TDD is the contract; opt out per project if needed.\nenforce_tdd: true\n\n# Test discovery globs — where spec-reviewer looks for REQ ID references in test files.\n# Detection is binary: the REQ ID literally appears in a test file or it doesn't.\ntest_globs:\n  - \"tests/**/*.test.{ts,js,tsx,jsx,mjs}\"\n  - \"tests/**/*.spec.{ts,js,tsx,jsx,mjs}\"\n  - \"__tests__/**/*\"\n  - \"test/**/*.test.{ts,js,tsx,jsx,mjs}\"\n  - \"**/*_test.{py,go,rb}\"\n  - \"**/test_*.py\"\n  - \"tests/e2e/**\"\n  - \"cypress/**\"\n  - \"playwright/**\"\n  - \"e2e/**\"\n\n# Forbidden content allowlist — which categories are acceptable inside REQs.\n# When false, the category is banned. When true, it's allowed.\nforbidden_content_allowlist:\n  protocols: true        # OAuth, JWT, WebSocket, etc.\n  vendors: true          # Cloudflare Access, Stripe, Resend, etc.\n  http_codes_in_api_reqs: true  # HTTP status codes when documenting an API contract REQ\n  performance_numbers: true  # \"p95 < 200ms\", \"LCP < 2.5s\"\n  user_facing_strings: true  # quoted text the user actually sees\n\n# Per-REQ overrides — REQ IDs that opt out of forbidden-content checks entirely\nforbidden_content_overrides: []\n\n# REQ length thresholds (in lines) — soft warnings only, never auto-fix\nreq_length:\n  warn: 25\n  medium: 50\n  high: 100\n",
    "modes": [
      "advanced"
    ]
